+  printer.PrintAttributeMap(op);
+  os << " -> ";
+  printer.PrintOpReturnType(op);
+  os << "{";
+  for (auto &item : forward_block()) {
+    os << "\n  ";
+    printer.PrintOperation(&item);
+  }
+  os << "\n }";
+}
