+              in_data, num, cin, cout, out_abs_max);
+      in_data += cout * max_threads;
+    }
+
+    int block = cin % max_threads;
+    if (block > 0) {
+      FindChannelAbsMaxKernelQuantAxis1<T>
+          <<<grid, block, block * sizeof(T), ctx.stream()>>>(
