-                                                              max_memory_size));
-      }
-    }
-#endif
-#ifdef PADDLE_WITH_CUSTOM_DEVICE
-    if (phi::is_custom_place(place)) {
-      if (framework::IsFastEagerDeletionModeEnabled()) {
-        gc.reset(new framework::CustomDeviceUnsafeFastGarbageCollector(
-            place, max_memory_size));
-      }
-    }
-#endif
-  }  // max_memory_size >= 0
-
-  return gc;
-}
