-  // create source and sink task node
-  int64_t max_run_times = static_cast<int64_t>(microbatch_scopes_.size());
-  TaskNode* source = new TaskNode(
-      rank_, SOURCE_ID, max_run_times);  // rank, task_id, max_run_times
